#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, Q;
        scanf("%d %d", &N, &Q);
        int A[N], B[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        for (int i = 0; i < N; i++) {
            scanf("%d", &B[i]);
        }
        while (Q--) {
            int x, y, l;
            scanf("%d %d %d", &x, &y, &l);
            long long sum = 0;
            for (int i = 0; i < l; i++) {
                sum += (long long)A[x + i - 1] * B[y + i - 1];
            }
            printf("%lld\n", sum);
        }
    }
    return 0;
}

