code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int Q = sc.nextInt();
            int[] A = new int[N];
            int[] B = new int[N];
            for (int i = 0; i < N; i++) {
                A[i] = sc.nextInt();
            }
            for (int i = 0; i < N; i++) {
                B[i] = sc.nextInt();
            }
            while (Q-- > 0) {
                int x = sc.nextInt();
                int y = sc.nextInt();
                int l = sc.nextInt();
                long sum = 0;
                for (int i = 0; i < l; i++) {
                    sum += (long)A[x + i - 1] * B[y + i - 1];
                }
                System.out.println(sum);
            }
        }
    }
}

